CREATE TABLE analysis_run (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  ts TEXT,
  session_name TEXT,
  trade_date TEXT,
  regime TEXT,
  input_summary_json TEXT,
  hard_rule_summary_json TEXT,
  llm_output_json TEXT,
  validated_output_json TEXT,
  report_json_path TEXT,
  report_md_path TEXT,
  status TEXT,
  error TEXT
);
CREATE TABLE backfill_result (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  signal_date TEXT,
  code TEXT,
  name TEXT,
  regime TEXT,
  score REAL,
  rule_result TEXT,
  reason TEXT,
  pct REAL,
  amount REAL,
  main_inflow REAL,
  main_inflow_pct REAL,
  amount_ratio_20 REAL,
  close_price REAL,
  next_open REAL,
  next_close REAL,
  return_1d_open REAL,
  return_1d_close REAL,
  return_5d REAL,
  return_10d REAL,
  return_20d REAL,
  hit_1d INTEGER,
  hit_5d INTEGER,
  hit_10d INTEGER,
  hit_20d INTEGER,
  source TEXT DEFAULT 'backfill',
  computed_at TEXT
);
CREATE TABLE backtest_result (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  signal_date TEXT,
  code TEXT,
  name TEXT,
  regime TEXT,
  score REAL,
  rule_result TEXT,
  reason TEXT,
  close_price REAL,
  next_open REAL,
  next_close REAL,
  return_1d_open REAL,
  return_1d_close REAL,
  return_5d REAL,
  return_10d REAL,
  hit_1d INTEGER,
  hit_5d INTEGER,
  hit_10d INTEGER,
  computed_at TEXT
);
CREATE TABLE decision_review (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  created_at TEXT,
  updated_at TEXT,
  analysis_run_id INTEGER,
  trade_date TEXT,
  session_name TEXT,
  code TEXT,
  name TEXT,
  original_decision TEXT,
  outcome_1d REAL,
  outcome_5d REAL,
  outcome_10d REAL,
  review_label TEXT,
  human_note TEXT,
  rule_adjustment_hint TEXT
);
CREATE TABLE etf_indicator (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  trade_date TEXT,
  code TEXT,
  ma5 REAL,
  ma10 REAL,
  ma20 REAL,
  ma60 REAL,
  ret5 REAL,
  ret10 REAL,
  ret20 REAL,
  amount_ratio_5 REAL,
  amount_ratio_20 REAL,
  above_ma5 INTEGER,
  above_ma10 INTEGER,
  above_ma20 INTEGER,
  ma20_slope_positive INTEGER
);
CREATE TABLE etf_master (
  code TEXT PRIMARY KEY,
  name TEXT,
  market TEXT,
  category TEXT,
  sub_category TEXT,
  is_broad INTEGER,
  is_theme INTEGER,
  is_qdii INTEGER,
  is_bond INTEGER,
  is_money INTEGER,
  status TEXT,
  updated_at TEXT
);
CREATE TABLE etf_snapshot (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  ts TEXT,
  trade_date TEXT,
  code TEXT,
  name TEXT,
  price REAL,
  pct REAL,
  amount REAL,
  volume REAL,
  main_inflow REAL,
  main_inflow_pct REAL,
  market_cap REAL,
  float_market_cap REAL
);
CREATE TABLE llm_decision (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  ts TEXT,
  session_name TEXT,
  decision_json TEXT,
  decision_md TEXT
);

