CREATE TABLE market_regime (
  trade_date TEXT PRIMARY KEY,
  above_ma20_ratio REAL,
  ma20_slope_positive_ratio REAL,
  inflow_positive_ratio REAL,
  regime TEXT
);
CREATE TABLE signal_result (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  ts TEXT,
  trade_date TEXT,
  session_name TEXT NOT NULL DEFAULT 'legacy',
  code TEXT,
  name TEXT,
  group_name TEXT,
  score REAL,
  rule_result TEXT,
  reason TEXT,
  entry_trigger TEXT,
  failure_condition TEXT
);
CREATE TABLE trade_log (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  entry_date TEXT,
  code TEXT,
  name TEXT,
  regime TEXT,
  pattern TEXT,
  direction_score REAL,
  entry_price REAL,
  stop_loss REAL,
  position_pct REAL,
  risk_amount REAL,
  exit_date TEXT,
  exit_price REAL,
  exit_reason TEXT,
  pnl REAL,
  pnl_pct REAL,
  mae REAL,
  mfe REAL,
  held_days INTEGER,
  notes TEXT
);
